    T_Oil_ONAF: [],
    T_Oil_OF: [],
    T_Oil_OD: [],
    T_Oil_limit: [],
    Load_factor: [],
    Intensity: [],
    T_Amb: []
  };
  for (let i = 1; i < 25; i++) {
    let tmpVal = JSObjectRes.res.value.filter(value => value.idShort === `P${i}`);
    tmpVal = tmpVal[0].value;
    tmpVal.forEach(value => {
      let val = value.value;
      if (value.idShort !== "time") {
        val = parseFloat(val).toFixed(2);
      }
      results[value.idShort].push(val);
    });
  }
  return results;
}

